                setSettingsId(null);
                // console.log('close')
            }
        }

        document.addEventListener('click', handleClickOutside);
        return () =>{
            document.removeEventListener('click', handleClickOutside)
        }
    }, [])

     useEffect(() =>{
         console.log(data)
    }, [data])

    const handleClickSettings = (e, notifId) =>{
